+    /// Create a seeded PRNG payload for cross-platform reproducibility.
+    fn seeded_payload(seed: u64, size: usize) -> Vec<u8> {
+        use rand::RngCore;
+        use rand::SeedableRng;
+        use rand_chacha::ChaCha20Rng;
+
